const body = $input.first().json.body;
const command = body.command || '/ai';
const rawText = (body.text || '').trim();
const userId = body.user_id || '';
const userName = body.user_name || 'unknown';
const channelId = body.channel_id || '';
const channelName = body.channel_name || '';
const responseUrl = body.response_url || '';

const AGENTS = ['kevin','jason','scaachi','christian','chidi'];
let agent = 'kevin';
let userText = rawText;

for (const a of AGENTS) {
  if (rawText.toLowerCase().startsWith(a + ':')) {
    agent = a;
    userText = rawText.slice(a.length + 1).trim();
    break;
  } else if (rawText.toLowerCase().startsWith(a + ' ')) {
    agent = a;
    userText = rawText.slice(a.length + 1).trim();
    break;
  }
}

if (agent === 'kevin' && userText === rawText) {
  for (const a of AGENTS) {
    if (channelName.includes(a)) { agent = a; break; }
  }
}

const MODEL_MAP = {
  kevin: 'kevin:latest',
  jason: 'jason:latest',
  scaachi: 'scaachi:latest',
  christian: 'christian:latest',
  chidi: 'chidi:latest'
};

return [{ json: {
  command, rawText, userText, userId, userName,
  channelId, channelName, responseUrl,
  agent,
  model: MODEL_MAP[agent] || 'kevin:latest'
}}];

// Convert common markdown to Slack mrkdwn
function mdToMrkdwn(text) {
  return text
    .replace(/^#{1,6}\s+(.+)$/gm, '*$1*')      // headings → bold
    .replace(/\*\*(.+?)\*\*/gs, '*$1*')          // **bold** → *bold*
    .replace(/__(.+?)__/gs, '*$1*')              // __bold__ → *bold*
    .replace(/~~(.+?)~~/gs, '~$1~')             // ~~strike~~ → ~strike~
    .replace(/\n{3,}/g, '\n\n')                  // collapse excess blank lines
    .trim();
}

// Agent emoji mapping
const AGENT_EMOJI = {
  kevin: ':briefcase:',
  jason: ':scales:',
  scaachi: ':pencil:',
  christian: ':compass:',
  chidi: ':bulb:'
};

const ollamaResp = $input.first().json;
const parsed = $('Parse Command').first().json;

const content = ollamaResp.message?.content || 'No response from model.';
const MAX = 2800;
const formatted = mdToMrkdwn(content);
const truncated = formatted.length > MAX
  ? formatted.slice(0, MAX) + '\n_[response truncated]_'
  : formatted;

const emoji = AGENT_EMOJI[parsed.agent] || ':robot_face:';
const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: emoji + ' ' + parsed.agent, emoji: true }
  },
  {
    type: 'context',
    elements: [{ type: 'mrkdwn', text: 'responding to <@' + parsed.userId + '>' }]
  },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn', text: truncated } },
  {
    type: 'context',
    elements: [{ type: 'mrkdwn', text: '_model: ' + (parsed.model || parsed.agent + ':latest') + '_' }]
  }
];

return [{ json: {
  responseUrl: parsed.responseUrl,
  agent: parsed.agent,
  userId: parsed.userId,
  slackPayload: JSON.stringify({
    response_type: 'in_channel',
    blocks
  })
}}];
